import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.Df0_fMVA.js";const u=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"privacy-policy.md","filePath":"privacy-policy.md"}'),r={name:"privacy-policy.md"};function n(s,e,l,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p><strong>Last updated:</strong> March 2, 2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Specialist Agent is an open-source CLI tool and plugin for AI-powered code editors. This Privacy Policy explains how data is handled by the tool itself and by this documentation website.</p><h2 id="the-cli-tool" tabindex="-1">The CLI Tool <a class="header-anchor" href="#the-cli-tool" aria-label="Permalink to &quot;The CLI Tool&quot;">​</a></h2><p>Specialist Agent operates <strong>entirely on your local machine</strong>. The tool:</p><ul><li>Does <strong>not</strong> collect, transmit, or store any personal data</li><li>Does <strong>not</strong> include telemetry or usage tracking</li><li>Does <strong>not</strong> communicate with any external servers on its own</li><li>Processes all files and code <strong>locally</strong> within your development environment</li></ul><h3 id="ai-provider-communication" tabindex="-1">AI Provider Communication <a class="header-anchor" href="#ai-provider-communication" aria-label="Permalink to &quot;AI Provider Communication&quot;">​</a></h3><p>When you use Specialist Agent through an AI-powered editor (Claude Code, Cursor, VS Code, etc.), your prompts and code context are sent to the <strong>AI provider</strong> (e.g., Anthropic, OpenAI) by the editor — not by Specialist Agent. These communications are governed by the respective AI provider&#39;s privacy policy:</p><ul><li><a href="https://www.anthropic.com/privacy" target="_blank" rel="noreferrer">Anthropic Privacy Policy</a></li><li><a href="https://openai.com/privacy" target="_blank" rel="noreferrer">OpenAI Privacy Policy</a></li></ul><h2 id="documentation-website" tabindex="-1">Documentation Website <a class="header-anchor" href="#documentation-website" aria-label="Permalink to &quot;Documentation Website&quot;">​</a></h2><p>This documentation website (<code>specialistagent.com.br</code>) may use analytics services to understand how visitors interact with the content. The data collected is anonymous and may include:</p><ul><li>Pages visited and navigation patterns</li><li>Approximate geographic location (country/region level)</li><li>Device type, browser, and operating system</li><li>Referral source</li><li>Time spent on pages</li></ul><p>This data is used solely to improve the documentation. No personally identifiable information is collected through analytics.</p><h3 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h3><p>This website may use cookies for:</p><ul><li><strong>Analytics</strong>: To measure website traffic and usage patterns</li><li><strong>Preferences</strong>: To remember your language selection (English / Portuguese)</li></ul><p>You can disable cookies through your browser settings at any time.</p><h3 id="hosting" tabindex="-1">Hosting <a class="header-anchor" href="#hosting" aria-label="Permalink to &quot;Hosting&quot;">​</a></h3><p>This website is hosted on <a href="https://docs.github.com/en/pages/getting-started-with-github-pages/about-github-pages#data-collection" target="_blank" rel="noreferrer">GitHub Pages</a>. GitHub may collect technical data such as IP addresses for security and operational purposes. See <a href="https://docs.github.com/en/site-policy/privacy-policies/github-general-privacy-statement" target="_blank" rel="noreferrer">GitHub&#39;s Privacy Statement</a> for details.</p><h2 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-Party Services&quot;">​</a></h2><p>Specialist Agent is distributed via <a href="https://www.npmjs.com/" target="_blank" rel="noreferrer">npm</a>. When you install the package using <code>npm install</code> or <code>npx</code>, npm may collect usage data as described in their <a href="https://docs.npmjs.com/policies/privacy" target="_blank" rel="noreferrer">privacy policy</a>.</p><h2 id="open-source" tabindex="-1">Open Source <a class="header-anchor" href="#open-source" aria-label="Permalink to &quot;Open Source&quot;">​</a></h2><p>Specialist Agent is released under the <a href="https://github.com/HerbertJulio/specialist-agent/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT License</a>. The full source code is publicly available for review on <a href="https://github.com/HerbertJulio/specialist-agent" target="_blank" rel="noreferrer">GitHub</a>.</p><h2 id="children-s-privacy" tabindex="-1">Children&#39;s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to &quot;Children&#39;s Privacy&quot;">​</a></h2><p>This tool and website are intended for software developers and are not directed at children under 13 years of age.</p><h2 id="changes-to-this-policy" tabindex="-1">Changes to This Policy <a class="header-anchor" href="#changes-to-this-policy" aria-label="Permalink to &quot;Changes to This Policy&quot;">​</a></h2><p>We may update this Privacy Policy from time to time. Changes will be reflected on this page with an updated &quot;Last updated&quot; date. For significant changes, a notice may be posted on the repository.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>If you have questions about this Privacy Policy, please open an issue on <a href="https://github.com/HerbertJulio/specialist-agent/issues" target="_blank" rel="noreferrer">GitHub</a> or contact the maintainer through their <a href="https://github.com/HerbertJulio" target="_blank" rel="noreferrer">GitHub profile</a>.</p>',30)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
